```class Solution {
public:
    int maxSubstrings(string word) {
        int n = word.length();
        int max_count = 0;
        for (int i = 0; i < n - 3; i++) {
            int count = 0;
            for (int j = i + 1; j < n; j++) {
                if (word[i] == word[j] && word[i + 1] == word[j + 1] && word[i + 2] == word[j + 2] && word[i + 3] == word[j + 3]) {
                    count++;
                }
            }
            max_count = max(max_count, count);
        }
        return max_count;
    }
};```

